#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-06

# Density scan: info / (info + decoration + ws) >= 0.20 per fenced ASCII
# block in src/skills/**/SKILL.md (mirrors ascii-lint density-min rule).
# Per-pattern overrides match tokens.json density_overrides.

set -euo pipefail

ROOT="$(cd "$(dirname "$0")/../.." && pwd)"
SKILLS_DIR="$ROOT/src/skills"
THRESHOLD="${ASCII_DENSITY_MIN:-0.20}"

fail=0
checked=0

# Density via python3 — handles unicode + float math reliably.
density() {
  python3 - <<'PYEOF'
import sys, re
text = sys.stdin.read()
info = len(re.findall(r'[A-Za-z0-9→←↑↓]', text))
boxes = sum(1 for c in text if 0x2500 <= ord(c) <= 0x257F)
ws = sum(1 for c in text if c.isspace())
total = info + boxes + ws
print(f"{(info/total) if total else 1.0:.3f}")
PYEOF
}

count_box() {
  printf '%s' "$1" | python3 -c '
import sys
print(sum(1 for c in sys.stdin.read() if 0x2500 <= ord(c) <= 0x257F))
'
}

scan_file() {
  local file="$1"
  local in_block=0
  local block=""
  local startline=0
  local lineno=0
  while IFS= read -r line; do
    lineno=$((lineno + 1))
    if [ "$in_block" = 0 ]; then
      case "$line" in '```'*) in_block=1; block=""; startline=$((lineno + 1)) ;; esac
    else
      case "$line" in
        '```'*)
          local box_count
          box_count=$(count_box "$block")
          if [ "${box_count:-0}" -ge 3 ]; then
            checked=$((checked + 1))
            local d
            d=$(printf '%s' "$block" | density)
            if awk -v d="$d" -v t="$THRESHOLD" 'BEGIN{ exit (d < t) ? 0 : 1 }'; then
              printf '⚠ %s:%d density %s < %s\n' "${file#$ROOT/}" "$startline" "$d" "$THRESHOLD"
              fail=$((fail + 1))
            fi
          fi
          in_block=0
          ;;
        *) block+="$line"$'\n' ;;
      esac
    fi
  done < "$file"
}

for file in "$SKILLS_DIR"/*/SKILL.md; do
  [ -f "$file" ] || continue
  scan_file "$file"
done

printf '\n✓ scanned %d block(s) · ⚠ %d below %s\n' "$checked" "$fail" "$THRESHOLD"
# Currently advisory: report but do not fail. Set ASCII_DENSITY_BLOCK=1 to enforce.
if [ "${ASCII_DENSITY_BLOCK:-0}" = "1" ] && [ "$fail" -gt 0 ]; then
  exit 1
fi
exit 0
